import{_ as t,o,c as s,a3 as i}from"./chunks/framework.CjquFG0V.js";const c=JSON.parse(`{"title":"9. Dispute Resolution","description":"","frontmatter":{"title":"9. Dispute Resolution","eba":"Children's Services Award 2010","topics":["leave","parental-leave","hours","right-to-disconnect","employment","disputes","flexible-work","preliminary"]},"headers":[],"relativePath":"ebas/childrens-services/consultation-disputes/9-dispute-resolution.md","filePath":"ebas/childrens-services/consultation-disputes/9-dispute-resolution.md"}`),a={name:"ebas/childrens-services/consultation-disputes/9-dispute-resolution.md"};function r(n,e,l,p,u,d){return o(),s("div",null,[...e[0]||(e[0]=[i('<h1 id="_9-dispute-resolution" tabindex="-1">9. Dispute Resolution <a class="header-anchor" href="#_9-dispute-resolution" aria-label="Permalink to &quot;9. Dispute Resolution&quot;">​</a></h1><ol><li><p>Clause 9 sets out the procedures to be followed if a dispute arises about a matter under this award or in relation to the <a href="https://www.fwc.gov.au/documents/awards/resources/nes.pdf" target="_blank" rel="noreferrer">NES</a>.</p></li><li><p>The parties to the dispute must first try to resolve the dispute at the workplace through discussion between the employee or employees concerned and the relevant supervisor.</p></li><li><p>If the dispute is not resolved through discussion as mentioned in clause 9.2, the parties to the dispute must then try to resolve it in a timely manner at the workplace through discussion between the employee or employees concerned and more senior levels of management, as appropriate.</p></li><li><p>If the dispute is unable to be resolved at the workplace and all appropriate steps have been taken under clauses 9.2 and 9.3, a party to the dispute may refer it to the Fair Work Commission.</p></li><li><p>The parties may agree on the process to be followed by the Fair Work Commission in dealing with the dispute, including mediation, conciliation and consent arbitration.</p></li><li><p>If the dispute remains unresolved, the Fair Work Commission may use any method of dispute resolution that it is permitted by the <a href="http://www.legislation.gov.au/Series/C2009A00028" target="_blank" rel="noreferrer">Act</a> to use and that it considers appropriate for resolving the dispute.</p></li><li><p>A party to the dispute may appoint a person, organisation or association to support and/or represent them in any discussion or process under clause 9.</p></li><li><p>While procedures are being followed under clause 9 in relation to a dispute:</p><p>a. work must continue in accordance with this award and the <a href="http://www.legislation.gov.au/Series/C2009A00028" target="_blank" rel="noreferrer">Act</a>; and</p><p>b. an employee must not unreasonably fail to comply with any direction given by the employer about performing work, whether at the same or another workplace, that is safe and appropriate for the employee to perform.</p></li><li><p>Clause 9.8 is subject to any applicable work health and safety legislation.</p></li></ol><p>NOTE: In addition to clause 9, the <a href="http://www.legislation.gov.au/Series/C2009A00028" target="_blank" rel="noreferrer">Act</a> contains dispute resolution procedures as follows:</p><p><strong>For a dispute about rights under the Act to</strong> <strong>Section</strong></p><hr><p>Request flexible working arrangements 65B Change casual employment status 66M Request an extension to unpaid parental leave 76B Exercise an employee&#39;s right to disconnect 333N</p><p>Plain language terms: grievance, FWC dispute.</p>',7)])])}const m=t(a,[["render",r]]);export{c as __pageData,m as default};
